#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[50001];
        scanf("%s", S);
        int M;
        scanf("%d", &M);
        while (M--) {
            int Li, Ri;
            scanf("%d %d", &Li, &Ri);
            int count = 0;
            for (int i = Li - 1; i < Ri; i++) {
                count += strlen(S) - i;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

