code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int M = sc.nextInt();
            while (M-- > 0) {
                int Li = sc.nextInt();
                int Ri = sc.nextInt();
                int count = 0;
                for (int i = Li - 1; i < Ri; i++) {
                    count += S.length() - i;
                }
                System.out.println(count);
            }
        }
    }
}

